# ---- Fin trailer ----


def main() -> None:
    if len(sys.argv) < 2:
        print("Uso: python {sys.argv[0]} <archivo_entrada>")
        sys.exit(1)

    input_path = sys.argv[1]
    with open(input_path, encoding="utf-8") as f:
        text = f.read()

    tokens, errors = tokenize(text)

    for token in tokens:
        print(token)

    if errors:
        print()
        for error in errors:
            print(error.message)
        sys.exit(1)


if __name__ == "__main__":
    main()
